#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long L,R,M; scanf("%lld %lld %lld", &L, &R, &M);
        long long pages = (M + L - 1) / L; // ceil(M/L)
        long long lines = M / R;           // floor(M/R)
        printf("%lld\n", pages + lines);
    }
    return 0;
}

